import{_ as e,o as r,c as t,R as n}from"./chunks/framework.ndjtv7DT.js";const b=JSON.parse('{"title":"区块链","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/33.web3/01.blockchain/index.md","filePath":"tutorials/33.web3/01.blockchain/index.md","lastUpdated":1689907217000}'),o={name:"tutorials/33.web3/01.blockchain/index.md"},a=n('<h1 id="区块链" tabindex="-1">区块链 <a class="header-anchor" href="#区块链" aria-label="Permalink to &quot;区块链&quot;">​</a></h1><p>在我们正式进入 Web3 世界前，我们需要了解 Web3 的核心 <strong>区块链 blockchain</strong> 和相关概念。</p><h2 id="基本概念" tabindex="-1">基本概念 <a class="header-anchor" href="#基本概念" aria-label="Permalink to &quot;基本概念&quot;">​</a></h2><p>你可以认为区块链是一个 <strong>公共交易数据库</strong>，由网络中的许多计算机更新和共享，这些运行着区块链应用的计算机被称为 <strong>节点 node</strong>，它们组成的 <strong>点对点网络 peer to peer network</strong> 是 <strong>去中心化网络 decentralized network</strong>，也可以称为节点网络。节点可以单独 <strong>验证和审计 verify and audit</strong> 数据，保证所有与区块链交互的人都有相同的数据，确保没有非法行为。</p><p><strong>区块 block</strong> 是基本的数据结构。每个区块都包含一组 <strong>交易 transaction</strong>，这些交易已经由节点网络通过 <strong>共识 consensus</strong> 进行了验证和记录。发起交易时，只有将交易数据成功添加到一个区块中，交易才算成功。</p><p><strong>链 chain</strong> 指的是区块被链接在一起，也可以说每个区块加密引用其父块。在不改变所有后续区块的情况下，区块内数据无法改变，但改变后续区块需要整个网络的共识，这几乎不可能达成，所以我们一般认为 <strong>区块一旦添加到链上就无法更改或删除</strong>，从而为网络上所有交易创建了 <strong>不可更改的记录</strong>。这也表示，网络的当前状态可以随时重新计算，从最开始的区块（创世区块）开始，根据每个区块到目前为止的信息进行状态转换即可。</p><p>我们常见的挖矿，其实就是指 <strong>挖矿节点 mining node</strong> 所做的工作。挖矿节点是另一类节点，它们将网络上进行的新交易 <strong>组合成一个区块</strong>，验证审计后建议其他所有人将该区块纳入链接中。挖矿的计算难度很大，而且安全挖矿非常重要，因此，区块被接受的挖矿者会因其辛勤工作而获得 <strong>代币 token</strong> 奖励。</p><p>区块链的使用解决了双重支付（又称一币多付、双花攻击，英文 double-spending）问题，同一笔数字货币不可能被重复花用两次或更多次。</p><p>区块链是在 2009 年中本聪发布比特币网络时开始推广的。随着时间推移，更多更强的区块链网络涌现，比如我们接下来主要学习的 <a href="https://ethereum.org/" target="_blank" rel="noreferrer">以太坊 Ethereum</a>。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://ethereum.org/zh/web3/" target="_blank" rel="noreferrer">以太坊 - Web3 简介</a></li><li><a href="https://learnweb3.io/degrees/ethereum-developer-degree/freshman/what-even-is-a-blockchain/" target="_blank" rel="noreferrer">LearnWeb3 - What even is a blockchain</a></li><li><a href="https://ethereum.org/zh/developers/docs/intro-to-ethereum/" target="_blank" rel="noreferrer">以太坊 - 以太坊简介</a></li></ul>',11),s=[a];function i(l,h,c,g,d,p){return r(),t("div",null,s)}const u=e(o,[["render",i]]);export{b as __pageData,u as default};
